import numpy as npimport mathfrom matplotlib import pyplotfrom pandas import read_csvfrom pandas import concatfrom pandas import DataFramefrom sklearn.preprocessing import MinMaxScalerfrom tensorflow.keras.models import Model, load_modelfrom tensorflow.keras.layers import GRU, Reshape, Input, concatenate, add, Dense, TimeDistributed, RepeatVectorimport sklearn.metrics as metricsfrom tensorflow.keras.optimizers import Adamfrom tensorflow.keras.utils import to_categoricalfrom tensorflow.keras.callbacks import EarlyStopping, ReduceLROnPlateauimport osimport randomfrom attention import Attentionfrom tensorflow.keras.initializers import GlorotUniformimport timeos.environ['PYTHONHASHSEED'] = '0'np.random.seed(2020)random.seed(2020)# ---------------------- load data -------------------- #def _load_dataset(file_path, header_row_index, index_col_name, col_to_predict):    """    file_path: the csv file path    header_row_index: the header row index in the csv file    index_col_name: the index column (can be None if no index is there)    col_to_predict: the column name/index to predict    """    # load data from file_path    dataset = read_csv(file_path, engine='python', header=header_row_index, index_col=index_col_name)    if index_col_name:        dataset.set_index(index_col_name, inplace=True)    # print(dataset)    # get rows and column names    col_names = dataset.columns.values.tolist()    values = dataset.values    # move the column to predict to be the first col    col_to_predict_index = col_to_predict if type(col_to_predict) == int else col_names.index(col_to_predict)    output_col_name = col_names[col_to_predict_index]    if col_to_predict_index > 0:        col_names = [col_names[col_to_predict_index]] + col_names[:col_to_predict_index] + col_names[                                                                                           col_to_predict_index + 1:]    values = np.concatenate((values[:, col_to_predict_index].reshape((values.shape[0], 1)),                             values[:, :col_to_predict_index], values[:, col_to_predict_index + 1:]), axis=1)    # ensure all data is float    values = values.astype("float32")    return col_names, values, values.shape[1], output_col_name# ---------------------- scale data ------------------------- #def _scale_dataset(values, scale_range):    """    values: dataset values    scale_range: scale range to fit data in    """    # normalize features    scaler = MinMaxScaler(feature_range=scale_range or (0, 1))    scaled = scaler.fit_transform(values)    return (scaler, scaled)# ------------- convert series to supervised learning ------------------- #def _series_to_supervised(values, n_in, n_out, dropnan, col_names, verbose):    """    values: dataset scaled values    n_in: number of time lags (intervals) to use in each neuron    n_out: number of time-steps in future to predict    dropnan: whether to drop rows with NaN values after conversion to supervised learning    col_names: name of columns for dataset    verbose: whether to output some debug data    """    n_vars = 1 if type(values) is list else values.shape[1]    if col_names is None: col_names = ["var%d" % (j + 1) for j in range(n_vars)]    df = DataFrame(values)    cols, names = list(), list()    # input sequence (t-n, ... t-1)    for i in range(n_in, 0, -1):        cols.append(df.shift(i))        names += [("%s(t-%d)" % (col_names[j], i)) for j in range(n_vars)]    for i in range(0, n_out):        cols.append(df.shift(-i))        if i == 0:            names += [("%s(t)" % (col_names[j])) for j in range(n_vars)]        else:            names += [("%s(t+%d)" % (col_names[j], i)) for j in range(n_vars)]    # put it all together    agg = concat(cols, axis=1)    agg.columns = names    # drop rows with NaN values    if dropnan:        agg.dropna(inplace=True)    # print(agg)    if verbose:        print("\nsupervised data shape:", agg.shape)    return agg# ------------------- split into train and test sets ------------------ #def _split_data_to_train_test_sets(values, n_intervals, n_features, n_out,                                    train_length, val_length, week,                                   holiday, weather, time_of_day):    """    values: dataset supervised values    n_intervals: number of time lags (intervals) to use in each neuron    n_features: number of features (variables) per neuron    n_out: number of time lags (intervals) to predict    train_length: length of train data related to the dataset series size    val_length: length of val data related to the dataset series size    week: day of week (external factor)    holiday: holiday (external factor)    weather: weather (external factor)    time_of_day: time of day (external factor)    """        # split into train, val, and test datasets    train = values[:train_length, :]    val = values[train_length:  val_length, :]    test = values[val_length:, :]        # split into input and outputs    obs = n_intervals * n_features    n_obs = [i + n_features * j for j in range(0, n_intervals) for i in range(1, n_features)]    n_obs_out = [obs - n_features * i for i in range(n_out, 0, -1)]    # split into X (the inputs of the prediction model) and y (the outputs of the prediction model)    train_X, train_y = train[:, n_obs], train[:, n_obs_out]    val_X, val_y = val[:, n_obs], val[:, n_obs_out]    test_X, test_y = test[:, n_obs], test[:, n_obs_out]    # reshape input to be 3D [samples, timesteps, features]    train_X = train_X.reshape((-1, n_intervals, n_features - 1))    test_X = test_X.reshape((-1, n_intervals, n_features - 1))    val_X = val_X.reshape((-1, n_intervals, n_features - 1))    train_y = train_y.reshape((-1, n_out, 1))    val_y = val_y.reshape((-1, n_out, 1))    test_y = test_y.reshape((-1, n_out, 1))    # use one-hot encoder the encode the external factors    week = to_categorical(week)    holiday = to_categorical(holiday)    weather = to_categorical(weather)    time_of_day = to_categorical(time_of_day)    # also split the external factors into train parts and test parts    train_week, val_week, test_week = week[n_intervals: train_length, :, :], \                                      week[train_length:val_length, :, :],\                                      week[val_length:, :, :]        train_holiday, val_holiday, test_holiday = holiday[n_intervals: train_length, :, :], \                                               holiday[train_length: val_length, :, :], \                                               holiday[val_length:, :, :]        train_weather, val_weather, test_weather = weather[n_intervals: train_length, :, :], \                                               weather[train_length: val_length, :, :], \                                               weather[val_length:, :, :]        train_time_of_day, val_time_of_day, test_time_of_day = time_of_day[n_intervals: train_length, :, :], \                                                           time_of_day[train_length: val_length, :, :], \                                                           time_of_day[val_length:, :, :]    return (train_X, train_y, val_X, val_y, test_X, test_y, train_week, val_week, test_week,            train_holiday, val_holiday, test_holiday,            train_weather, val_weather, test_weather, train_time_of_day, val_time_of_day, test_time_of_day)# create the SA-S2S modeldef _create_model(train_X, train_y, test_X, test_y, n_neurons, n_batch, n_epochs, loss_function, draw_loss_plot,                  output_col_name, verbose, train_week, val_week, train_weather, val_weather,                  train_time_of_day, val_time_of_day, train_holiday, val_holiday, n_out_timestep):    """    train_X: train inputs    train_y: train targets    test_X: test inputs    test_y: test targets    n_neurons: number of neurons for GRU nn    n_batch: nn batch size    n_epochs: training epochs    loss_function: the model loss function evaluator    optimizer_function: the loss optimizer function    draw_loss_plot: whether to draw the loss history plot    output_col_name: name of the output/target column to be predicted    verbose: whether to output some debug data    train_week: train day-of-week    val_week: val day-of-week    train_weather: train weather    val_weather: val weather    train_time_of_day: train time-of-day    val_time_of_day: val time-of-day    train_holiday: train holiday    val_holiday: val holiday    n_out_timestep: prediction horizon    """    # -------------------------- set the callbacks ---------------------------------- #    # my_callback is the early stop callback setting    my_callback = EarlyStopping(monitor='val_loss', patience=50, verbose=0, mode='min')    # my_callback_2 is the auto learning rate tunning setting, if the loss function donot     # improve or decrease for 20 epoches (patience), the learning rate will reduce 0.5 of the original one    my_callback_2 = ReduceLROnPlateau(monitor='val_loss', patience=20, mode='min', factor=0.5)    # -------------------------- creat the model ----------------------------------- #    # input the stochastic part and feed into the GRU encoders    stochastic_inputs = Input(shape=(train_X.shape[1], 1), name='stochastic_inputs')    gru_1 = GRU(units=n_neurons, return_sequences=True, )(stochastic_inputs)    gru_1_2 = GRU(units=n_neurons, return_sequences=True, )(gru_1)    # input the deterministic part and feed into the GRU encoders    deterministic_inputs = Input(shape=(train_X.shape[1], 1), name='deterministic_inputs')    gru_2 = GRU(units=n_neurons, return_sequences=True, )(deterministic_inputs)    gru_2_2 = GRU(units=n_neurons, return_sequences=True, )(gru_2)    # input the trend part and feed into the GRU encoders    trend_inputs = Input(shape=(train_X.shape[1], 1), name='trend_inputs')    gru_3 = GRU(units=n_neurons, return_sequences=True, )(trend_inputs)    gru_3_2 = GRU(units=n_neurons, return_sequences=True, )(gru_3)    # input the external factors, feed into the GRU layer, and concatenate them into the External_layer_1    week_inputs = Input(shape=(train_week.shape[1], train_week.shape[2]), name='week_inputs')    weather_inputs = Input(shape=(train_weather.shape[1], train_weather.shape[2]), name='weather_inputs')    time_inputs = Input(shape=(train_time_of_day.shape[1], train_time_of_day.shape[2]), name='time_inputs')    holiday_inputs = Input(shape=(train_holiday.shape[1], train_holiday.shape[2]), name='holiday')    week = GRU(16, return_sequences=False)(week_inputs)       weather = GRU(16, return_sequences=False)(weather_inputs)    time = GRU(16, return_sequences=False)(time_inputs)    holiday = GRU(16, return_sequences=False)(holiday_inputs)    external_1 = concatenate([week, weather, time, holiday])    external_1 = RepeatVector(n_out_timestep)(external_1)    # add attention layers for the stochastic_inputs according to the n_out_timesteps    attention_1_1, score_1_1 = Attention(return_attention=True)(gru_1_2)    attention_1_2, score_1_2 = Attention(return_attention=True)(gru_1_2)    attention_1_3, score_1_3 = Attention(return_attention=True)(gru_1_2)    attention_1_4, score_1_4 = Attention(return_attention=True)(gru_1_2)    attention_1_5, score_1_5 = Attention(return_attention=True)(gru_1_2)    attention_1_6, score_1_6 = Attention(return_attention=True)(gru_1_2)    attention_1 = concatenate([attention_1_1, attention_1_2, attention_1_3,                                attention_1_4, attention_1_5, attention_1_6], axis=1)    attention_1 = Reshape((n_out_timestep, -1))(attention_1)    # add attention layers for the deterministic_inputs according to the n_out_timesteps    attention_2_1, score_2_1 = Attention(return_attention=True)(gru_2_2)    attention_2_2, score_2_2 = Attention(return_attention=True)(gru_2_2)    attention_2_3, score_2_3 = Attention(return_attention=True)(gru_2_2)    attention_2_4, score_2_4 = Attention(return_attention=True)(gru_2_2)    attention_2_5, score_2_5 = Attention(return_attention=True)(gru_2_2)    attention_2_6, score_2_6 = Attention(return_attention=True)(gru_2_2)    attention_2 = concatenate([attention_2_1, attention_2_2, attention_2_3,                               attention_2_4, attention_2_5, attention_2_6], axis=1)    attention_2 = Reshape((n_out_timestep, -1))(attention_2)        # add attention layers for the trend_inputs according to the n_out_timesteps    attention_3_1, score_3_1 = Attention(return_attention=True)(gru_3_2)    attention_3_2, score_3_2 = Attention(return_attention=True)(gru_3_2)    attention_3_3, score_3_3 = Attention(return_attention=True)(gru_3_2)    attention_3_4, score_3_4 = Attention(return_attention=True)(gru_3_2)    attention_3_5, score_3_5 = Attention(return_attention=True)(gru_3_2)    attention_3_6, score_3_6 = Attention(return_attention=True)(gru_3_2)    attention_3 = concatenate([attention_3_1, attention_3_2, attention_3_3,                               attention_3_4, attention_3_5, attention_3_6], axis=1)    attention_3 = Reshape((n_out_timestep, -1))(attention_3)    # add attention layers    add_ = add([attention_1, attention_2, attention_3])    # fusion the external factors    fusion = concatenate([add_, external_1])    # decoders    gru_4 = GRU(n_neurons, return_sequences=True, )(fusion)    gru_5 = GRU(n_neurons, return_sequences=True, )(gru_4)    time_dis = TimeDistributed(Dense(1))(gru_5)    # select Adam as the optimizer_function    optimizer_function = Adam(lr=0.001)    # construct the model    model = Model(inputs=[stochastic_inputs, deterministic_inputs, trend_inputs,                          week_inputs, weather_inputs, time_inputs, holiday_inputs],                  outputs=time_dis)    print(model.summary())    # compile the model    model.compile(loss=loss_function, optimizer=optimizer_function)    if verbose:        print("")    # fit network    history = model.fit([train_X[:, :, 0].reshape(-1, n_in_timestep, 1),                         train_X[:, :, 1].reshape(-1, n_in_timestep, 1),                         train_X[:, :, 2].reshape(-1, n_in_timestep, 1),                         train_week, train_weather, train_time_of_day, train_holiday],                        train_y, epochs=n_epochs, batch_size=n_batch,                        validation_data=([test_X[:, :, 0].reshape(-1, n_in_timestep, 1),                                          test_X[:, :, 1].reshape(-1, n_in_timestep, 1),                                          test_X[:, :, 2].reshape(-1, n_in_timestep, 1),                                          val_week, val_weather, val_time_of_day, val_holiday],                                         test_y),                        callbacks=[my_callback, my_callback_2], verbose=2)    # plot the loss    if draw_loss_plot:        pyplot.plot(history.history["loss"], label="Train Loss (%s)" % output_col_name)        pyplot.plot(history.history["val_loss"], label="Val Loss (%s)" % output_col_name)        pyplot.legend()        pyplot.show()    return model# make a predictiondef _make_prediction(test_X, test_y, n_intervals, n_features, scaler, n_out, yhat):    """    test_X: test inputs    test_y: test targets    n_intervals: number of time lags (intervals) to use in each neuron    n_features: number of features (variables) per neuron    scaler: the scaler object used to invert transformation to real scale    n_out:    """    test_X = test_X.reshape((test_X.shape[0], n_intervals * (n_features - 1)))    inv_yhat_ = np.ones(shape=test_y.shape)    inv_y_ = np.ones(shape=test_y.shape)    for i in range(n_out):        # invert scaling for forecast        inv_yhat = np.concatenate((yhat[:, i].reshape(-1, 1), test_X[:, (1 - n_features):]), axis=1)        inv_yhat = scaler.inverse_transform(inv_yhat)        inv_yhat_[:, i] = inv_yhat[:, 0]        test_y = test_y.reshape((len(test_y), n_out))        inv_y = np.concatenate((test_y[:, i].reshape(-1, 1), test_X[:, (1 - n_features):]), axis=1)        inv_y = scaler.inverse_transform(inv_y)        inv_y_[:, i] = inv_y[:, 0]    inv_y = inv_y_[:, :]    inv_yhat = inv_yhat_[:, :]    return (inv_y, inv_yhat)def eva_regress(y_true, y_pred):    """Evaluation    evaluate the predicted resul.    # Arguments        y_true: List/ndarray, ture data.        y_pred: List/ndarray, predicted data.    """    mae = metrics.mean_absolute_error(y_true, y_pred)    mse = metrics.mean_squared_error(y_true, y_pred)    print('rmse:%f' % math.sqrt(mse))    print('mae:%f' % mae)    return math.sqrt(mse), maedef week(n_out_timestep):    week = []    for i in range(8):        for k in range(7):            for j in range(210):                week.append(k)    week = week[:-n_out_timestep + 1]    return np.array(week).reshape((-1, 1, 1))def holiday(n_out_timestep):    holiday = []    for i in range(210 * 5):        holiday.append(0)    for i in range(210 * 2):        holiday.append(1)    holiday_seq = []    for i in range(8):        for k in holiday:            holiday_seq.append(k)    holiday = np.array(holiday_seq[:-n_out_timestep + 1])    return holiday.reshape((-1, 1, 1))def weather(n_out_timestep):    weather = [1, 1, 1, 1, 1, 1, 1, 2, 3, 2, 3, 3, 2, 3, 3, 1, 1, 3, 3, 4, 2, 2, 3, 3, 1, 3,               1, 1, 1, 3, 5, 3, 3, 3, 5, 5, 5, 5, 5, 3, 1, 3, 3, 5, 4, 4, 3, 3, 6, 5, 4, 4, 5,               3, 3, 5]    weather_mon = []    for i in weather:        for j in range(210):            weather_mon.append(i)    weather_mon = weather_mon[:-n_out_timestep + 1]    return np.array(weather_mon).reshape((-1, 1, 1))def time_of_day(n_out_timestep):    time = []    time_of_day = []    for i in range(18):        time.append(0)    for i in range(72 - 18):        time.append(1)    for i in range(72, 210 - 24):        time.append(2)    for i in range(24):        time.append(3)    for j in range(8):        for i in range(7):            for k in time:                time_of_day.append(k)    time_of_day = time_of_day[: -n_out_timestep + 1]    return np.array(time_of_day).reshape((-1, 1, 1))file_path = 'ensemble_data_S1_out.csv'header_row_index = 0index_col_name = 0index = ['stochastic', 'deterministic', 'trend', 'ori']col_to_predict = 'ori'col_names, values, n_features, output_col_name = _load_dataset(file_path, header_row_index,                                                               index_col_name, col_to_predict)scaler, values = _scale_dataset(values, None)n_in_timestep = 12n_out_timestep = 6verbose = 0dropnan = Truen_neurons = 64n_batch = 128n_epochs = 400train_percentage = - 22 * 210val_percentage = - 11 * 210loss_function = 'mae'optimizer_function = 'adam'draw_loss_plot = Trueweek = week(n_out_timestep)holiday = holiday(n_out_timestep)weather = weather(n_out_timestep)time_of_day = time_of_day(n_out_timestep)agg1 = _series_to_supervised(values, n_in_timestep, n_out_timestep, dropnan, col_names, verbose)train_X, train_Y, val_X, val_Y, test_X, test_Y, train_week, val_week, test_week, train_holiday, val_holiday, \test_holiday, train_weather, val_weather, test_weather, train_time_of_day, val_time_of_day, test_time_of_day = \    _split_data_to_train_test_sets(agg1.values, n_in_timestep, n_features, n_out_timestep,                                   train_percentage, val_percentage, week, holiday, weather, time_of_day)t_start_time = time.time()# model = _create_model(train_X, train_Y, val_X, val_Y, n_neurons, n_batch, n_epochs,loss_function,#                                           draw_loss_plot, output_col_name, verbose, train_week, val_week, train_weather,#                                           val_weather, train_time_of_day,val_time_of_day, train_holiday, val_holiday,#                                           n_out_timestep)t_end_time = time.time()t_time = t_end_time - t_start_timeprint("+================================================")print('Training time: %s' % t_time)p_start_time = time.time()# load the trained modelmodel = load_model('DEASeq2Seq_6step_S1_out.h5',                                    custom_objects={'Attention': Attention, 'GlorotUniform': GlorotUniform})yhat = model.predict([test_X[:, :, 0].reshape(-1, n_in_timestep, 1),                                       test_X[:, :, 1].reshape(-1, n_in_timestep, 1),                                       test_X[:, :, 2].reshape(-1, n_in_timestep, 1),                                       test_week, test_weather, test_time_of_day, test_holiday],                                      batch_size=n_batch, verbose=0 if verbose else 0)p_end_time = time.time()p_time = p_end_time - p_start_timeprint("+================================================")print('Prediction time: %s' % t_time)yhat = yhat.reshape(2310, n_out_timestep)test_Y = test_Y.reshape(2310, n_out_timestep)actual_target, predicted_target = _make_prediction(test_X, test_Y, n_in_timestep, n_features, scaler, n_out_timestep, yhat)rsme, mae = eva_regress(actual_target, predicted_target)